        _tracker.Transfer("SKU-1", 20, "WH-A", "WH-B");

        Assert.AreEqual(30, _tracker.GetStockLevel("SKU-1", "WH-A"));
        Assert.AreEqual(20, _tracker.GetStockLevel("SKU-1", "WH-B"));
    }

