    public void Transfer_TotalStockUnchanged()
    {
        _tracker.AddStock("SKU-1", 100, "WH-A");

        int before = _tracker.GetStockLevel("SKU-1");
        _tracker.Transfer("SKU-1", 40, "WH-A", "WH-B");
        int after = _tracker.GetStockLevel("SKU-1");

        Assert.AreEqual(before, after);
    }

    [TestMethod]
    public void Transfer_EntireStock_LeavesSourceEmpty()
    {
        _tracker.AddStock("SKU-1", 25, "WH-A");
        _tracker.Transfer("SKU-1", 25, "WH-A", "WH-B");

        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-1", "WH-A"));
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-1", "WH-B"));
    }

    [TestMethod]
    public void Transfer_InsufficientStock_Throws()
    {
        _tracker.AddStock("SKU-1", 10, "WH-A");

        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.Transfer("SKU-1", 15, "WH-A", "WH-B"));
    }

    [TestMethod]
    public void Transfer_InsufficientStock_DoesNotModifyDestination()
    {
        _tracker.AddStock("SKU-1", 10, "WH-A");
        _tracker.AddStock("SKU-1", 5, "WH-B");

        try { _tracker.Transfer("SKU-1", 15, "WH-A", "WH-B"); }
        catch (InvalidOperationException) { }

        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-1", "WH-A"));
        Assert.AreEqual(5, _tracker.GetStockLevel("SKU-1", "WH-B"));
    }

    [TestMethod]
    public void Transfer_SameWarehouse_Throws()
    {
        _tracker.AddStock("SKU-1", 10, "WH-A");

        Assert.ThrowsException<ArgumentException>(
            () => _tracker.Transfer("SKU-1", 5, "WH-A", "WH-A"));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-3)]
    public void Transfer_NonPositiveQuantity_Throws(int qty)
    {
        _tracker.AddStock("SKU-1", 10, "WH-A");

        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.Transfer("SKU-1", qty, "WH-A", "WH-B"));
    }

    [TestMethod]
    public void Transfer_CanTriggerReorderAlert()
    {
        _tracker.SetReorderThreshold("SKU-1", 10);
        _tracker.AddStock("SKU-1", 30, "WH-A");

        Assert.IsFalse(_tracker.NeedsReorder("SKU-1"));

        // Transfer leaves only 5 globally (WH-A: 5, WH-B: 25)
        // but total is still 30 — need to move to a different sku config
        // Instead: remove some first, then transfer the rest out
        _tracker.RemoveStock("SKU-1", 22, "WH-A");
        _tracker.Transfer("SKU-1", 5, "WH-A", "WH-B");

        // Total is 3 (WH-A) + 5 (WH-B) = 8 ≤ 10
        Assert.IsTrue(_tracker.NeedsReorder("SKU-1"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void Transfer_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.Transfer(sku!, 1, "WH-A", "WH-B"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void Transfer_InvalidSourceWarehouse_Throws(string? wh)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.Transfer("SKU-1", 1, wh!, "WH-B"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void Transfer_InvalidDestWarehouse_Throws(string? wh)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.Transfer("SKU-1", 1, "WH-A", wh!));
    }
}

