    public void Transfer_TotalStockUnchanged()
    {
        _tracker.AddStock("SKU-1", 100, "WH-A");

        int before = _tracker.GetStockLevel("SKU-1");
        _tracker.Transfer("SKU-1", 40, "WH-A", "WH-B");
        int after = _tracker.GetStockLevel("SKU-1");

        Assert.AreEqual(before, after);
    }

    [TestMethod]
    public void Transfer_EntireStock_LeavesSourceEmpty()
    {
        _tracker.AddStock("SKU-1", 25, "WH-A");
        _tracker.Transfer("SKU-1", 25, "WH-A", "WH-B");

        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-1", "WH-A"));
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-1", "WH-B"));
    }

    [TestMethod]
    public void Transfer_InsufficientStock_Throws()
    {
        _tracker.AddStock("SKU-1", 10, "WH-A");

        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.Transfer("SKU-1", 15, "WH-A", "WH-B"));
    }

    [TestMethod]
    public void Transfer_InsufficientStock_DoesNotModifyDestination()
    {
        _tracker.AddStock("SKU-1", 10, "WH-A");
        _tracker.AddStock("SKU-1", 5, "WH-B");

        try { _tracker.Transfer("SKU-1", 15, "WH-A", "WH-B"); }
        catch (InvalidOperationException) { }

        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-1", "WH-A"));
        Assert.AreEqual(5, _tracker.GetStockLevel("SKU-1", "WH-B"));
    }

    [TestMethod]
    public void Transfer_SameWarehouse_Throws()
    {
        _tracker.AddStock("SKU-1", 10, "WH-A");

        Assert.ThrowsException<ArgumentException>(
