    {
        _tracker.AddStock("SKU-1", 10, "WH-A");

        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.Transfer("SKU-1", qty, "WH-A", "WH-B"));
    }

    [TestMethod]
    public void Transfer_CanTriggerReorderAlert()
    {
        _tracker.SetReorderThreshold("SKU-1", 10);
        _tracker.AddStock("SKU-1", 30, "WH-A");

        Assert.IsFalse(_tracker.NeedsReorder("SKU-1"));

        // Transfer leaves only 5 globally (WH-A: 5, WH-B: 25)
        // but total is still 30 — need to move to a different sku config
        // Instead: remove some first, then transfer the rest out
        _tracker.RemoveStock("SKU-1", 22, "WH-A");
        _tracker.Transfer("SKU-1", 5, "WH-A", "WH-B");

        // Total is 3 (WH-A) + 5 (WH-B) = 8 ≤ 10
        Assert.IsTrue(_tracker.NeedsReorder("SKU-1"));
    }

