    [DataRow(null)]
    [DataRow("")]
    public void Transfer_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.Transfer(sku!, 1, "WH-A", "WH-B"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void Transfer_InvalidSourceWarehouse_Throws(string? wh)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.Transfer("SKU-1", 1, wh!, "WH-B"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void Transfer_InvalidDestWarehouse_Throws(string? wh)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.Transfer("SKU-1", 1, "WH-A", wh!));
    }
}
