+
+        Assert.IsFalse(_tracker.NeedsReorder("SKU-1"));
+
+        // Transfer leaves only 5 globally (WH-A: 5, WH-B: 25)
+        // but total is still 30 — need to move to a different sku config
+        // Instead: remove some first, then transfer the rest out
+        _tracker.RemoveStock("SKU-1", 22, "WH-A");
